      if (source === 'ingredients' || q1Param === 'ingredients') {
        quizData.q1 = 'ingredients';
        setTimeout(() => {
          const option = document.querySelector('#step1 .wizard-option[data-value="ingredients"]');
          if (option) option.click();
        }, 100);
      } else if (source === 'waste' || q1Param === 'waste') {
        quizData.q1 = 'waste';
        setTimeout(() => {
          const option = document.querySelector('#step1 .wizard-option[data-value="waste"]');
          if (option) option.click();
        }, 100);
