    // =========================
    // WIZARD LOGIC
    // =========================

    function getDefaultQ3ForNotSure() {
      if (quizData.q1 === 'ingredients') return ['ingredients', 'swaps', 'everyday'];
      if (quizData.q1 === 'waste') return ['packaging', 'swaps', 'everyday'];
      return ['ingredients', 'packaging', 'swaps', 'everyday'];
    }

    function selectOption(key, value, currentStep, nextStep, el) {
      if (key === 'q1') {
        quizData.q1 = value;
        trackEvent('quiz_q1_completed', { answer: value });
      } else if (key === 'q2') {
        quizData.q2 = value;
        trackEvent('quiz_q2_completed', { answer: value });
      }

      document.querySelectorAll(`#${currentStep} .wizard-option`).forEach(opt => opt.classList.remove('selected'));
      if (el) el.classList.add('selected');

      updateProgress(currentStep);

      if (key === 'q2' && value === 'not-sure') {
        if (!quizData.q3 || quizData.q3.length === 0) quizData.q3 = getDefaultQ3ForNotSure();
        trackEvent('quiz_q3_autofilled', { answers: quizData.q3, reason: 'not_sure_path' });
        trackEvent('quiz_completed', quizData);

        setTimeout(() => {
          goToStep(currentStep, 'results');
          updateProgress('results');
          showRecommendations();
        }, 200);
        return;
      }

      setTimeout(() => goToStep(currentStep, nextStep), 300);
    }

    function toggleMultiSelect(key, value, element, autoProceed = false) {
      const index = quizData.q3.indexOf(value);
      const wasEmptyBefore = quizData.q3.length === 0;

      if (index > -1) {
        quizData.q3.splice(index, 1);
        element.classList.remove('selected');
        return;
      } else {
        quizData.q3.push(value);
        element.classList.add('selected');
      }

      if (autoProceed && wasEmptyBefore && !step3AutoNavigated) {
        step3AutoNavigated = true;

        trackEvent('quiz_q3_completed', { answers: quizData.q3 });
        trackEvent('quiz_completed', quizData);

        setTimeout(() => {
          goToStep('step3', 'results');
          updateProgress('results');
          showRecommendations();
        }, 220);
      }
    }

    function goToStep(fromStep, toStep) {
      document.getElementById(fromStep).classList.remove('active');
      document.getElementById(toStep).classList.add('active');

      if (toStep !== 'results') {
        document.getElementById('quiz').scrollIntoView({ behavior: 'smooth', block: 'start' });
      } else {
        document.getElementById('results').scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    }

    function updateProgress(currentStep) {
      if (currentStep === 'results') {
        for (let i = 1; i <= 3; i++) {
          const dot = document.getElementById(`progress-${i}`);
          if (dot) dot.classList.add('active');
        }
        return;
      }

      const stepNum = currentStep.replace('step', '');
      const stepInt = parseInt(stepNum, 10);

      for (let i = 1; i <= 3; i++) {
        const dot = document.getElementById(`progress-${i}`);
        if (dot) dot.classList.toggle('active', i <= stepInt);
      }
    }

    function resetWizard() {
      quizData = { q1: null, q2: null, q3: [] };
      step3AutoNavigated = false;
      document.querySelectorAll('.wizard-option').forEach(opt => opt.classList.remove('selected'));
      document.querySelectorAll('.wizard-step').forEach(step => step.classList.remove('active'));
      document.getElementById('step1').classList.add('active');
      updateProgress('step1');
      trackEvent('quiz_reset');
    }

    function showRecommendations() {
      const container = document.getElementById('recommendations');
      let categoryProducts = [];

      let selectedProducts;
      if (quizData.q1 === 'ingredients') selectedProducts = product1;
      else if (quizData.q1 === 'waste') selectedProducts = product2;
      else if (quizData.q1 === 'both') selectedProducts = product3;
      else selectedProducts = product1;

      if (quizData.q2 === 'not-sure') categoryProducts = selectedProducts['not-sure'];
      else categoryProducts = selectedProducts[quizData.q2] || [];

      let filtered = categoryProducts.filter(product => {
        if (quizData.q1 === 'ingredients' && !product.ingredients) return false;
        if (quizData.q1 === 'waste' && !product.packaging) return false;
        if (quizData.q1 === 'both' && (!product.ingredients || !product.packaging)) return false;

        if (quizData.q3.length > 0) {
          const matches = quizData.q3.some(priority => product[priority]);
          if (!matches) return false;
        }
        return true;
      });

      filtered = filtered.slice(0, 12);

      if (filtered.length === 0) {
        container.innerHTML =
          '<p style="text-align:center;color:var(--muted);padding:2rem">No products match your criteria. <a data-gtm-cta="shopify" href="https://memotherearthbrand.com/" target="_blank" style="color:var(--brand)">Browse all products</a></p>';
        return;
      }

      container.innerHTML = filtered.map(product => `
        <div class="variant-card" onclick="selectProduct('${product.id}')">
          <div class="variant-image">
            <img src="${product.image}" alt="${product.name}"
              onerror="this.src='https://via.placeholder.com/400x400?text=${encodeURIComponent(product.name)}'">
          </div>
          <div class="variant-info">
            <div class="why-match">${product.why}</div>
            <h3>${product.name}</h3>
            <p>${getProductDescription(product)}</p>
            <div class="price">${product.price}</div>
            <a data-gtm-cta="shopify" href="https://memotherearthbrand.com/products/${product.id}" target="_blank" class="btn outline"
              style="margin-top:1rem;display:inline-block;padding:0.8rem 1.5rem;font-size:0.9rem"
              onclick="event.stopPropagation(); trackEvent('product_clicked', {product_id: '${product.id}'})">Learn More</a>
          </div>
        </div>
      `).join('');

      trackEvent('results_viewed', { product_count: filtered.length });
    }

    function getProductDescription(product) {
      const descriptions = [];
      if (product.ingredients && quizData.q3.includes('ingredients')) descriptions.push('Ingredient-conscious, thoughtfully selected');
      if (product.packaging && quizData.q3.includes('packaging')) descriptions.push('Plastic-free or low-waste packaging');
      if (product.swaps && quizData.q3.includes('swaps')) descriptions.push('Simple swap for everyday routines');
      if (product.everyday && quizData.q3.includes('everyday')) descriptions.push('Designed for daily use');
      return descriptions.join(' • ') || 'Thoughtful eco-friendly alternative';
    }

    function selectProduct(id) {
      trackEvent('product_selected', { product_id: id });
      window.open(`https://memotherearthbrand.com/products/${id}`, '_blank');
    }

    function trackEvent(eventName, data = {}) {
      if (typeof gtag !== 'undefined') gtag('event', eventName, data);
      if (typeof fbq !== 'undefined') fbq('track', eventName, data);
      console.log('Event:', eventName, data);
    }

    document.addEventListener('DOMContentLoaded', function () {
      initializeFromURL();

      document.querySelectorAll('a[href^="#"]').forEach(anchor => {
        anchor.addEventListener('click', function (e) {
          e.preventDefault();
          const target = document.querySelector(this.getAttribute('href'));
          if (target) target.scrollIntoView({ behavior: 'smooth', block: 'start' });
        });
      });
    });
